import json

# Load reviewed list
reviewed_raw = locals()['var_function-call-1880734423617911372']
if isinstance(reviewed_raw, str):
    with open(reviewed_raw, 'r') as f:
        reviewed_raw = json.load(f)

# Extract IDs and convert to businessid_ format
target_ids = []
for item in reviewed_raw:
    ref = item['business_ref']
    # ref is businessref_X, we need businessid_X
    # Assuming the suffix X is the same.
    suffix = ref.split('_')[1]
    target_ids.append(f"businessid_{suffix}")

# Create the Mongo query
query = {
    "collection": "business",
    "filter": {
        "business_id": {"$in": target_ids}
    },
    "projection": {
        "business_id": 1,
        "attributes": 1
    }
}

print("__RESULT__:")
print(json.dumps(query))

