import json
import ast

# Load results
# reviewed_raw is not strictly needed since I filtered in query, but good for sanity check if I wanted.
# I will just process the business list.
business_file = locals()['var_function-call-13752562615741184350']

with open(business_file, 'r') as f:
    businesses = json.load(f)

def check_business_parking(val):
    if val is None:
        return False
    if isinstance(val, str):
        if val == 'None':
            return False
        if val == 'True':
            return True
        if val == 'False':
            return False
        # Try parsing dict string
        if val.startswith('{'):
            try:
                # ast.literal_eval can handle standard python dict strings
                d = ast.literal_eval(val)
                if isinstance(d, dict):
                    # Check if any value is truthy (True)
                    # The values in the dict might be booleans or strings 'True'/'False'?
                    # In the preview: 'garage': False. They are booleans.
                    # But let's be safe.
                    for k, v in d.items():
                        if v is True:
                            return True
                        if isinstance(v, str) and v == 'True':
                            return True
            except:
                pass
    return False

def check_bike_parking(val):
    if val is None:
        return False
    if isinstance(val, str):
        if val == 'True':
            return True
    return False

count = 0
for bus in businesses:
    attrs = bus.get('attributes')
    if not attrs or attrs == 'None':
        continue

    # attrs is a dict
    if isinstance(attrs, dict):
        bp = attrs.get('BikeParking')
        cp = attrs.get('BusinessParking')

        has_bike = check_bike_parking(bp)
        has_car = check_business_parking(cp)

        if has_bike or has_car:
            count += 1

print("__RESULT__:")
print(count)

